simple.afterForm:
[
    {
        "type": "divider"
    },
    {
        "type": "panel",
        "title": "查询结果",
        "visibleOn": "this.symbol != null",
        "body": [
            {
                "type": "alert",
                "level": "info",
                "body": "当前符号: ${symbol.qualifiedName | default:'-'} (${symbol.kind | default:'-'})"
            },
            {
                "type": "panel",
                "title": "调用者 (Callers)",
                "visibleOn": "this.callers != null && this.callers.length > 0",
                "collapsable": true,
                "body": {
                    "type": "input-tree",
                    "name": "callers",
                    "multiple": false,
                    "showIcon": true,
                    "initiallyOpen": false,
                    "valueField": "symbol.qualifiedName",
                    "labelField": "label",
                    "childrenField": "children",
                    "source": "${callers | map: item => ({ label: item.symbol.qualifiedName + ' (' + item.symbol.kind + ')', children: [].concat(item.callers || [], item.callees || []) }) }",
                    "searchable": true
                }
            },
            {
                "type": "panel",
                "title": "被调用者 (Callees)",
                "visibleOn": "this.callees != null && this.callees.length > 0",
                "collapsable": true,
                "body": {
                    "type": "input-tree",
                    "name": "callees",
                    "multiple": false,
                    "showIcon": true,
                    "initiallyOpen": false,
                    "valueField": "symbol.qualifiedName",
                    "labelField": "label",
                    "childrenField": "children",
                    "source": "${callees | map: item => ({ label: item.symbol.qualifiedName + ' (' + item.symbol.kind + ')', children: [].concat(item.callers || [], item.callees || []) }) }",
                    "searchable": true
                }
            }
        ]
    }
]
